//#region src/assets/form.js
var schemas = { contact: {
	action: "/api/contact",
	fields: [
		{
			name: "name",
			type: "text",
			label: "Name",
			required: true
		},
		{
			name: "email",
			type: "email",
			label: "Email",
			required: true
		},
		{
			name: "message",
			type: "textarea",
			label: "Message",
			required: true,
			minLength: 10
		}
	]
} };
function renderField(field) {
	const { name, type, label, required, minLength } = field;
	const attrs = [
		`name="${name}"`,
		`id="field-${name}"`,
		required ? "required" : "",
		minLength ? `minlength="${minLength}"` : ""
	].filter(Boolean).join(" ");
	return `<div class="form-field" data-name="${name}">
  <label for="field-${name}">${label}</label>
  ${type === "textarea" ? `<textarea ${attrs}></textarea>` : `<input type="${type}" ${attrs}>`}
  <span class="form-error" aria-live="polite"></span>
</div>`;
}
function renderForm(schema) {
	return `${schema.fields.map(renderField).join("\n")}
<button type="submit" class="form-submit">Send</button>
<p class="form-status" aria-live="polite"></p>`;
}
function validate(field, value) {
	if (field.required && !value.trim()) return `${field.label} is required`;
	if (field.type === "email" && value && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)) return "Enter a valid email";
	if (field.minLength && value.length < field.minLength) return `Minimum ${field.minLength} characters`;
	return null;
}
//#endregion
//#region src/entry-server.js
function injectForms(html) {
	return html.replace(/(<form[^>]*\sdata-form="([^"]+)"[^>]*>)[\s\S]*?(<\/form>)/g, (_, open, name, close) => {
		const schema = schemas[name];
		if (!schema) {
			console.warn(`[form] no schema found for "${name}"`);
			return _;
		}
		return `${open}\n${renderForm(schema)}\n${close}`;
	});
}
var projectPage = (p) => `
<div class="project">
  <h1 class="chars">${p.title}</h1>
  <p>${p.year}</p>
  ${p.imgs.map((src) => `<img src="${src}" width="2400" height="1600" loading="lazy">`).join("\n  ")}
  <video src="https://interactive-examples.mdn.mozilla.net/media/cc0-videos/flower.mp4" width="1920" height="1080" loop loading="lazy" muted playsinline controls></video>
  <a href="/">← Back</a>
</div>`;
var processedRoutes = Object.fromEntries(Object.entries({
	"/": {
		html: home_default,
		title: "Home",
		prefetch: true
	},
	"/about": {
		html: about_default,
		title: "About",
		prefetch: true
	},
	"/contact": {
		html: contact_default,
		title: "Contact"
	}
}).map(([url, { html, title, prefetch }]) => [url, {
	body: splitText(injectForms(html)),
	title,
	...prefetch && { prefetch }
}]));
for (const p of projects) processedRoutes[`/${p.slug}`] = {
	body: splitText(projectPage(p)),
	title: p.title,
	...p.prefetch && { prefetch: true }
};
function render(url) {
	return processedRoutes[url] ?? {
		body: "<pre>404</pre>",
		title: "404"
	};
}
function renderAll() {
	return Object.fromEntries(Object.keys(processedRoutes).map((url) => [url, render(url)]));
}
//#endregion
export { layout_default as layout, render, renderAll, schemas, validate };
